import React, { useState } from "react";
import axios from "axios";
import { useParams } from "react-router-dom";

const EnrollForm = () => {
  const { id } = useParams();  // Get course ID from URL
  const [status, setStatus] = useState("");

  const enroll = () => {
    axios
      .post(`http://localhost:5000/api/courses/${id}/enroll`, {}, { 
        headers: {
          Authorization: `Bearer <Your-Token-Here>`  // Add the token to the request headers
        }
      })
      .then((response) => {
        setStatus("Enrollment successful!");
      })
      .catch((error) => {
        setStatus("Error enrolling in the course.");
        console.error("There was an error enrolling:", error);
      });
  };

  return (
    <div>
      <h2>Enroll in this course</h2>
      <button onClick={enroll}>Enroll</button>
      {status && <p>{status}</p>}
    </div>
  );
};

export default EnrollForm;
